//#region src/components/schedules/schedule-edit-utils.ts
function updateScheduleConditions(schedule, fields) {
	const conds = extractScheduleConds(schedule._conditions);
	const updateCond = (cond, op, field, value) => {
		if (cond) return {
			...cond,
			value
		};
		if (value != null || field === "payee") return {
			op,
			field,
			value
		};
		return null;
	};
	if (fields.date == null) return {
		error: t("Date is required"),
		conditions: []
	};
	if (fields.amount == null) return {
		error: t("A valid amount is required"),
		conditions: []
	};
	return { conditions: [
		updateCond(conds.payee, "is", "payee", fields.payee),
		updateCond(conds.account, "is", "account", fields.account),
		updateCond(conds.date, "isapprox", "date", fields.date),
		{
			op: fields.amountOp || "isapprox",
			field: "amount",
			value: fields.amount
		}
	].filter((val) => !!val) };
}
