function createScheduleEditReducer(useGetScheduledAmount = false) {
	return (state, action) => {
		switch (action.type) {
			case "set-schedule": {
				const schedule = action.schedule;
				const conds = extractScheduleConds(schedule._conditions);
				const condsSet = new Set(Object.values(conds));
				const isCustom = !!(schedule._conditions?.find((c) => !condsSet.has(c)) || schedule._actions?.find((a) => a.op !== "link-schedule"));
				return {
					...state,
					schedule: action.schedule,
					isCustom,
					fields: {
						payee: schedule._payee ?? null,
						account: schedule._account ?? null,
						amount: schedule._amount || 0,
						amountOp: schedule._amountOp || "isapprox",
						date: schedule._date ?? null,
						posts_transaction: action.schedule.posts_transaction ?? false,
						name: schedule.name ?? null
					}
				};
			}
			case "set-field": {
				if (!(action.field in state.fields)) throw new Error("Unknown field: " + action.field);
				const fields = { [action.field]: action.value };
				if (action.field === "amountOp" && action.value !== state.fields.amountOp) {
					if (action.value === "isbetween") if (useGetScheduledAmount) {
						const num = getScheduledAmount(state.fields.amount);
						fields.amount = {
							num1: num,
							num2: num
						};
					} else fields.amount = typeof state.fields.amount === "number" ? {
						num1: state.fields.amount,
						num2: state.fields.amount
					} : {
						num1: 0,
						num2: 0
					};
					else if (state.fields.amountOp === "isbetween") if (useGetScheduledAmount) fields.amount = getScheduledAmount(state.fields.amount);
					else fields.amount = typeof state.fields.amount === "number" ? state.fields.amount : state.fields.amount?.num1;
				}
				return {
					...state,
					fields: {
						...state.fields,
						...fields
					}
				};
			}
			case "set-transactions": {
				const transactions = action.transactions;
				if (action.transactionId && transactions) transactions.sort((a, b) => (action.transactionId === b.id ? 1 : 0) - (action.transactionId === a.id ? 1 : 0));
				return {
					...state,
					transactions
				};
			}
			case "set-repeats": {
				if (!action.repeats) return {
					...state,
					fields: {
						...state.fields,
						date: currentDay()
					}
				};
				const date = {
					start: currentDay(),
					frequency: "monthly",
					patterns: [],
					skipWeekend: false,
					weekendSolveMode: "after",
					endMode: "never",
					endOccurrences: 1,
					endDate: currentDay()
				};
				return {
					...state,
					fields: {
						...state.fields,
						date
					}
				};
			}
			case "set-upcoming-dates": return {
				...state,
				upcomingDates: action.dates
			};
			case "form-error": return {
				...state,
				error: action.error
			};
			case "switch-transactions": return {
				...state,
				transactionsMode: action.mode
			};
			default: throw new Error("Unknown action");
		}
	};
}
